    local height = self.lvGoodsList:getHeight()
    local width = (height / 117) * 136
    self.goodsAdapter:setItemSize(width, height)
    self.lvGoodsList:setAdapter(self.goodsAdapter)

    local llGoodsGroup = self:getChildWindow("BedWarUpgradeStore-Group-BG")
    local lvGoodsGroup = IGUIListView.new("BedWarUpgradeStore-Group-List", llGoodsGroup)
    lvGoodsGroup:setArea({ 0, 12 }, { 0, 12 }, { 1, -24 }, { 1, -24 })
    lvGoodsGroup:setItemSpace(10)
    local contentWidth = lvGoodsGroup:getWidth()
    self.goodsGroupAdapter = (require "game.ui.adapter.UpgradeGoodsDescAdapter").new()
    self.goodsGroupAdapter:setItemSize(contentWidth, 57)
    lvGoodsGroup:setAdapter(self.goodsGroupAdapter)

    local tvTitleText = self:getChildWindow("BedWarUpgradeStore-Title-Text", GUIType.StaticText)
