function UIUpgradeStore:isShowAnim()
    return false
end

function UIUpgradeStore:show(playSound)
    if playSound then
        SoundUtil.playSound(SoundConfig.openStore)
    end
    self.super.show(self, playSound)
end

function UIUpgradeStore:hide(playSound)
    if playSound then
        SoundUtil.playSound(SoundConfig.closeStore)
    end
    self.super.hide(self)
end

function UIUpgradeStore:onBuyGoodsSuccess(goods)
    local count = GoodsStorePrivilege:onBuyGoods(goods)
    if #goods.Image > 10 then
        HostApi.notifyGetGoods(goods.Image, count)
    else
        HostApi.notifyGetItem(goods.ItemId, 0, count)
    end
end

function UIUpgradeStore:updateListUI()
    if not self:isShow() then
        return
    end
    if not self.curSelectGoods then
        return
    end
    local info = GameInfoManager:getTeamInfo(Game:getPlayer():getTeamId())
    if not info then
        return
    end
    local level = tonumber(info:getValue(self.curSelectGoods.ItemId))
    if level ~= self.curSelectGoods.Level - 1 then
        local _goods = StoreConfig:getUpgradeGoods(self.curSelectGoods.ItemId, self.curSelectGoods.Level + 1)
        if _goods then
            self:showGoodsDetail(_goods)
        end
    end
    self.goodsAdapter:notifyDataChange()
    self.goodsGroupAdapter:notifyDataChange()
end

function UIUpgradeStore:onTick()
    for _, item in pairs(self.lvMoney.items) do
        item:onTick()
    end
end

function UIUpgradeStore:onShow()
    self:updateListUI()
    if self.curSelectGoods then
        return
    end
    local config = StoreConfig:getStoreConfig(StoreId.UpgradeStore)
    if not config then
        return
    end
    self.lvMoney:clearItems()
    for _, data in pairs(config.CurrencyList) do
        local money = GUICurrency.new("BedWarCurrency.json")
        money:onDataChanged(data)
        self.lvMoney:addItem(money)
    end
    if #config.Tabs > 0 then
        if #config.Tabs[1].GoodsList > 1 then
            self:showGoodsDetail(config.Tabs[1].GoodsList[1])
        end
        self.goodsAdapter:setData(config.Tabs[1].GoodsList)
    end
end

function UIUpgradeStore:onTick()
    for _, item in pairs(self.lvMoney.items) do
        item:onTick()
    end
end

function UIUpgradeStore:showGoodsDetail(goods)
    if self.curSelectGoods == goods then
        return
    end
    local oldGoods = self.curSelectGoods
    self.curSelectGoods = nil
    self.goodsAdapter:notifyItemDataChange(oldGoods)
    self.curSelectGoods = goods
    ClientStore:setGoodsUI(self.tvGoodsName, self.ivGoodsImage, self.ivGoodsMoneyIcon, self.tvGoodsMoneyText, self.btnGoodsBuy, goods)
    self.goodsAdapter:notifyItemDataChange(goods)
    local group = StoreConfig:getGoodsGroup(self.curSelectGoods.LevelGroup)
    self.goodsGroupAdapter:setData(group)
    GameAnalytics:design(1, { "select_upgradeshop", tostring(goods.Id) })
end

function UIUpgradeStore:getCurrentGoodsId()
    if self.curSelectGoods then
        return self.curSelectGoods.Id
    end
    return 0
end

function UIUpgradeStore:showTips(tips)
    self.tvTips:SetText(tips)
    self.tvTips:SetVisible(true)
    LuaTimer:cancel(self.curTipKey)
    self.curTipKey = LuaTimer:schedule(function()
        self.tvTips:SetVisible(false)
    end, 1000)
end

function UIUpgradeStore:onBuyGoods(goods)
    ClientStore:onBuyGoods(goods, function(success, tips)
        if tips and #tips > 0 then
            self:showTips(tips)
        end
    end)
end

return UIUpgradeStore